 {"id":"cass_memory_system-0ew.9","title":"Reflect Command: cass-memory reflect (Full Pipeline)","description":"# Feature: Reflect Command (Full Pipeline Orchestration)

## Purpose
Orchestrate the full diary → reflect → validate → curate pipeline.
This is the command that makes the playbook learn from recent sessions.

## Usage
```bash
cass-memory reflect --days 7 --max-sessions 10
cass-memory reflect --dry-run --json  # See what would happen
cass-memory reflect --session ~/.claude/sessions/abc.jsonl  # Single session
```

## Process Flow
```
1. Find unprocessed sessions (not in processed.log)
2. For each session:
   a. Generate diary (if not exists)
   b. Run reflector (extract deltas)
   c. Run validator on "add" deltas (evidence gate + LLM)
   d. Apply deltas via curator
   e. Mark session as processed
3. Save updated playbook
4. Run auto-prune
5. Check for anti-pattern inversions
```

## Implementation
```typescript
async function reflectCommand(flags: ReflectFlags): Promise<void> {
  const config = await loadConfig();
  const playbook = await loadMergedPlaybook(config);

  // 1. Find sessions to process
  const sessions = flags.session
    ? [{ path: flags.session, agent: detectAgent(flags.session) }]
    : await findUnprocessedSessions(config);

  if (sessions.length === 0) {
    output({ message: "No new sessions to process" }, null, flags);
    return;
  }

  const results: ReflectionResult[] = [];

  // 2. Process each session
  for (const session of sessions.slice(0, flags.maxSessions || 10)) {
    // 2a. Generate diary
    let diary = await loadDiary(session.path);
    if (!diary) {
      diary = await generateDiary(session.path, session.agent, config);
      await saveDiary(diary);
    }

    // 2b. Run reflector
    const deltas = await reflectOnSession(diary, playbook, config);

    // 2c. Validate "add" deltas
    const validatedDeltas: Delta[] = [];
    for (const delta of deltas) {
      if (delta.type === "add" && config.validationEnabled) {
        const validation = await validateRule(delta.bullet.content, config);
        if (validation.valid) {
          // Optionally use refined content
          if (validation.refinedContent) {
            delta.bullet.content = validation.refinedContent;
          }
          validatedDeltas.push(delta);
        }
      } else {
        validatedDeltas.push(delta);
      }
    }

    // 2d. Dry run check
    if (flags.dryRun) {
      results.push({
        session: session.path,
        diary,
        proposedDeltas: validatedDeltas,
        applied: false
      });
      continue;
    }

    // 2e. Apply deltas
    const { applied, skipped } = curatePlaybook(playbook, validatedDeltas, config);

    // 2f. Mark processed
    await markSessionProcessed(session.path);

    results.push({
      session: session.path,
      diary,
      proposedDeltas: validatedDeltas,
      applied: true,
      deltasApplied: applied,
      deltasSkipped: skipped
    });
  }

  // 3. Save playbook (if not dry run)
  if (!flags.dryRun) {
    // Run anti-pattern inversion check
    checkAndInvertAntiPatterns(playbook, config);

    // Auto-prune
    const pruned = autoPrunePlaybook(playbook, config);

    await savePlaybook(playbook, config.playbookPath);

    output({
      sessionsProcessed: results.length,
      results,
      pruned
    }, formatReflectResult, flags);
  } else {
    output({
      dryRun: true,
      sessionsAnalyzed: results.length,
      results
    }, formatReflectDryRun, flags);
  }
}
```

